export const DELIVERY_FEE = 3.50;

import { GoogleGenAI, Type } from "@google/genai";
import { Product, CartItem } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const geminiService = {
  async generateJuiceDescription(juiceName: string, ingredients: string[]): Promise<string> {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Write a short (max 15 words), appetizing, and fresh marketing description for a juice called "${juiceName}" containing ${ingredients.join(', ')}.`,
      });
      return response.text || "Freshly squeezed daily just for you.";
    } catch (error) {
      console.error("AI Error:", error);
      return "Nutritious and delicious fresh-pressed juice.";
    }
  },

  async getChatResponse(query: string, storeInfo: string): Promise<string> {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: query,
        config: {
          systemInstruction: `You are a friendly juice shop assistant at FreshPress.
          Store info: ${storeInfo}.
          Rules:
          - Be brief and helpful.
          - If asked about menu, mention our signature Green Glow.
          - We offer Pickup and Delivery.
          - Delivery fee is $3.50.
          - Open 8am-8pm daily.`,
        }
      });
      return response.text || "I'm sorry, I'm having a bit of trouble connecting. How else can I help you today?";
    } catch (error) {
      return "We're currently juicing some fresh oranges! Please try your question again in a moment.";
    }
  },

  async getUpsellSuggestion(cartItems: CartItem[], allProducts: Product[]): Promise<Product | null> {
    try {
      if (cartItems.length === 0) return null;

      const cartNames = cartItems.map(i => i.name).join(', ');
      const availableNames = allProducts.map(p => p.name).join(', ');

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Based on items in cart: [${cartNames}], suggest exactly ONE juice from this list: [${availableNames}] that complements them well. Return only the juice name.`,
      });

      const suggestedName = response.text?.trim();
      return allProducts.find(p => p.name.toLowerCase().includes(suggestedName?.toLowerCase() || '')) || null;
    } catch (error) {
      return null;
    }
  },

  async generateConfirmationMessage(customerName: string, type: string): Promise<string> {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate a short, enthusiastic 2-sentence confirmation message for ${customerName} who just placed a ${type} order.`,
      });
      return response.text || "Thank you for your order! We're starting on your fresh juice right now.";
    } catch (error) {
      return "Your order has been received! We'll have it ready for you shortly.";
    }
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { geminiService } from '../services/geminiService';

const ChatBot: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{ role: 'user' | 'bot'; text: string }[]>([
    { role: 'bot', text: 'Hi! I am your FreshPress assistant. Ask me anything about our juices, hours, or delivery!' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    const botResponse = await geminiService.getChatResponse(userMsg, "Open 8am-8pm, located at 123 Juice St, delivery $3.50.");
    setMessages(prev => [...prev, { role: 'bot', text: botResponse }]);
    setIsLoading(false);
  };

  return (
    <div className="fixed bottom-6 right-6 z-50">
      {isOpen ? (
        <div className="bg-white rounded-2xl shadow-2xl w-80 sm:w-96 flex flex-col overflow-hidden border border-slate-200">
          <div className="bg-emerald-600 p-4 text-white flex justify-between items-center">
            <h3 className="font-semibold flex items-center gap-2">
              <i className="fas fa-robot"></i> FreshBot Assistant
            </h3>
            <button onClick={() => setIsOpen(false)}><i className="fas fa-times"></i></button>
          </div>
          <div ref={scrollRef} className="h-80 overflow-y-auto p-4 space-y-4 bg-slate-50">
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] p-3 rounded-2xl text-sm ${
                  msg.role === 'user' ? 'bg-emerald-500 text-white rounded-tr-none' : 'bg-white border border-slate-200 text-slate-700 rounded-tl-none shadow-sm'
                }`}>
                  {msg.text}
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border border-slate-200 p-3 rounded-2xl rounded-tl-none shadow-sm text-slate-400">
                  <i className="fas fa-circle-notch animate-spin"></i> Thinking...
                </div>
              </div>
            )}
          </div>
          <div className="p-4 bg-white border-t flex gap-2">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Type a message..."
              className="flex-1 bg-slate-100 rounded-full px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500"
            />
            <button 
              onClick={handleSend}
              className="bg-emerald-600 text-white w-10 h-10 rounded-full flex items-center justify-center hover:bg-emerald-700 transition-colors"
            >
              <i className="fas fa-paper-plane"></i>
            </button>
          </div>
        </div>
      ) : (
        <button 
          onClick={() => setIsOpen(true)}
          className="bg-emerald-600 text-white w-14 h-14 rounded-full shadow-lg flex items-center justify-center hover:scale-105 active:scale-95 transition-all"
        >
          <i className="fas fa-comment-dots text-xl"></i>
        </button>
      )}
    </div>
  );
};

export default ChatBot;

import React, { useState, useEffect, useMemo } from 'react';
import { Product, CartItem, Order, Page, OrderType, OrderStatus } from './types';
import { INITIAL_PRODUCTS, DELIVERY_FEE } from './constants';
import { geminiService } from './services/geminiService';
import ChatBot from './components/ChatBot';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [lastOrder, setLastOrder] = useState<Order | null>(null);

  // Checkout Form State
  const [customerName, setCustomerName] = useState('');
  const [phone, setPhone] = useState('');
  const [orderType, setOrderType] = useState<OrderType>('Pickup');
  const [address, setAddress] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [aiUpsell, setAiUpsell] = useState<Product | null>(null);

  // Cart Logic
  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (productId: string) => {
    setCart(prev => prev.filter(item => item.id !== productId));
  };

  const updateQuantity = (productId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === productId) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const cartSubtotal = useMemo(() => cart.reduce((sum, item) => sum + (item.price * item.quantity), 0), [cart]);
  const cartTotal = useMemo(() => cartSubtotal + (orderType === 'Delivery' ? DELIVERY_FEE : 0), [cartSubtotal, orderType]);

  // AI Upsell on Cart/Checkout
  useEffect(() => {
    if (cart.length > 0 && currentPage === 'checkout') {
      const getUpsell = async () => {
        const suggestion = await geminiService.getUpsellSuggestion(cart, products);
        setAiUpsell(suggestion);
      };
      getUpsell();
    } else {
      setAiUpsell(null);
    }
  }, [cart, currentPage, products]);

  const placeOrder = async () => {
    if (!customerName || !phone || (orderType === 'Delivery' && !address)) {
      alert("Please fill in all required fields.");
      return;
    }

    setIsProcessing(true);
    // Simulate payment processing (Stripe placeholder)
    await new Promise(resolve => setTimeout(resolve, 2000));

    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9).toUpperCase(),
      customerName,
      phone,
      items: [...cart],
      total: cartTotal,
      type: orderType,
      address: orderType === 'Delivery' ? address : undefined,
      status: 'New',
      createdAt: Date.now()
    };

    setOrders(prev => [newOrder, ...prev]);
    setLastOrder(newOrder);
    setCart([]);
    setCustomerName('');
    setPhone('');
    setAddress('');
    setIsProcessing(false);
    setCurrentPage('confirmation');
  };

  const updateOrderStatus = (orderId: string, newStatus: OrderStatus) => {
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: newStatus } : o));
  };

  // Views
  const renderHome = () => (
    <div className="flex flex-col items-center justify-center min-h-[80vh] text-center px-4">
      <div className="relative mb-8 group">
        <img 
          src="https://images.unsplash.com/photo-1610970881699-44a5587cabec?auto=format&fit=crop&q=80&w=600" 
          alt="Fresh Juice" 
          className="w-48 h-48 sm:w-64 sm:h-64 rounded-full object-cover border-8 border-white shadow-2xl transition-transform group-hover:scale-105"
        />
        <div className="absolute -bottom-4 -right-4 bg-orange-400 text-white p-4 rounded-full shadow-lg transform rotate-12">
          <p className="font-bold text-lg">100% Raw</p>
        </div>
      </div>
      <h1 className="text-5xl font-extrabold text-slate-800 mb-4 tracking-tight">FreshPress</h1>
      <p className="text-xl text-slate-600 mb-10 max-w-md mx-auto">
        Vibrant, cold-pressed juices delivered straight to your doorstep or ready for pickup.
      </p>
      <button 
        onClick={() => setCurrentPage('menu')}
        className="bg-emerald-600 text-white px-10 py-5 rounded-full font-bold text-xl shadow-xl hover:bg-emerald-700 active:scale-95 transition-all flex items-center gap-3"
      >
        <i className="fas fa-shopping-basket"></i> Order Now
      </button>
    </div>
  );

  const renderMenu = () => (
    <div className="max-w-6xl mx-auto px-4 py-12">
      <div className="flex justify-between items-center mb-12">
        <h2 className="text-3xl font-bold text-slate-800">Our Squeezes</h2>
        <div className="bg-emerald-100 text-emerald-800 px-4 py-2 rounded-full text-sm font-semibold">
          Daily Specials Available
        </div>
      </div>
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
        {products.map(product => (
          <div key={product.id} className="bg-white rounded-3xl overflow-hidden shadow-md hover:shadow-xl transition-shadow border border-slate-100 flex flex-col">
            <div className="h-48 relative overflow-hidden">
              <img src={product.image} alt={product.name} className="w-full h-full object-cover" />
              <div className="absolute top-4 right-4 bg-white/90 backdrop-blur px-3 py-1 rounded-full font-bold text-emerald-700">
                ${product.price.toFixed(2)}
              </div>
            </div>
            <div className="p-6 flex flex-col flex-1">
              <h3 className="text-xl font-bold text-slate-800 mb-2">{product.name}</h3>
              <p className="text-slate-500 text-sm mb-4 line-clamp-2">{product.description}</p>
              <div className="flex flex-wrap gap-1 mb-6">
                {product.ingredients.slice(0, 3).map((ing, i) => (
                  <span key={i} className="bg-slate-50 text-slate-400 text-[10px] uppercase tracking-wider px-2 py-1 rounded-md">
                    {ing}
                  </span>
                ))}
              </div>
              <button 
                onClick={() => addToCart(product)}
                className="mt-auto w-full bg-emerald-600 text-white py-3 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-emerald-700 active:scale-95 transition-all shadow-sm"
              >
                <i className="fas fa-plus"></i> Add to Cart
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const renderCart = () => (
    <div className="max-w-3xl mx-auto px-4 py-12">
      <h2 className="text-3xl font-bold text-slate-800 mb-8">Your Fresh Bag</h2>
      {cart.length === 0 ? (
        <div className="bg-white rounded-3xl p-12 text-center border-2 border-dashed border-slate-200">
          <i className="fas fa-shopping-cart text-5xl text-slate-200 mb-4"></i>
          <p className="text-slate-400 mb-6">Your bag is feeling a bit light...</p>
          <button 
            onClick={() => setCurrentPage('menu')}
            className="bg-emerald-600 text-white px-8 py-3 rounded-full font-bold"
          >
            Browse Menu
          </button>
        </div>
      ) : (
        <div className="space-y-4">
          {cart.map(item => (
            <div key={item.id} className="bg-white p-4 rounded-3xl flex items-center gap-4 shadow-sm border border-slate-100">
              <img src={item.image} alt={item.name} className="w-20 h-20 rounded-2xl object-cover" />
              <div className="flex-1">
                <h4 className="font-bold text-slate-800">{item.name}</h4>
                <p className="text-emerald-600 font-semibold">${item.price.toFixed(2)}</p>
              </div>
              <div className="flex items-center gap-3 bg-slate-100 rounded-2xl px-3 py-2">
                <button onClick={() => updateQuantity(item.id, -1)} className="text-slate-500 hover:text-emerald-600"><i className="fas fa-minus"></i></button>
                <span className="font-bold w-6 text-center">{item.quantity}</span>
                <button onClick={() => updateQuantity(item.id, 1)} className="text-slate-500 hover:text-emerald-600"><i className="fas fa-plus"></i></button>
              </div>
              <button onClick={() => removeFromCart(item.id)} className="text-slate-300 hover:text-red-400 px-2">
                <i className="fas fa-trash"></i>
              </button>
            </div>
          ))}

          <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 mt-8 space-y-4">
            <div className="flex justify-between text-slate-500">
              <span>Subtotal</span>
              <span>${cartSubtotal.toFixed(2)}</span>
            </div>
            <div className="border-t border-slate-100 pt-4 flex justify-between text-xl font-bold text-slate-800">
              <span>Total</span>
              <span>${cartSubtotal.toFixed(2)}</span>
            </div>
            <button 
              onClick={() => setCurrentPage('checkout')}
              className="w-full bg-emerald-600 text-white py-5 rounded-2xl font-bold text-lg hover:bg-emerald-700 shadow-lg mt-4"
            >
              Checkout
            </button>
          </div>
        </div>
      )}
    </div>
  );

  const renderCheckout = () => (
    <div className="max-w-4xl mx-auto px-4 py-12 grid grid-cols-1 lg:grid-cols-2 gap-12">
      <div className="space-y-8">
        <h2 className="text-3xl font-bold text-slate-800">Checkout</h2>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 space-y-6">
          <h3 className="font-bold text-slate-800 border-b pb-4">Customer Info</h3>
          <div className="space-y-4">
            <div>
              <label className="text-sm font-semibold text-slate-500 block mb-1">Full Name</label>
              <input 
                type="text" 
                value={customerName}
                onChange={(e) => setCustomerName(e.target.value)}
                placeholder="Jane Doe" 
                className="w-full bg-slate-50 border-none rounded-2xl px-4 py-3 focus:ring-2 focus:ring-emerald-500" 
              />
            </div>
            <div>
              <label className="text-sm font-semibold text-slate-500 block mb-1">Phone Number</label>
              <input 
                type="tel" 
                value={phone}
                onChange={(e) => setPhone(e.target.value)}
                placeholder="(555) 000-0000" 
                className="w-full bg-slate-50 border-none rounded-2xl px-4 py-3 focus:ring-2 focus:ring-emerald-500" 
              />
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 space-y-6">
          <h3 className="font-bold text-slate-800 border-b pb-4">Delivery Options</h3>
          <div className="grid grid-cols-2 gap-4">
            <button 
              onClick={() => setOrderType('Pickup')}
              className={`p-4 rounded-2xl border-2 font-bold flex flex-col items-center gap-2 transition-all ${orderType === 'Pickup' ? 'border-emerald-500 bg-emerald-50 text-emerald-700' : 'border-slate-100 text-slate-400'}`}
            >
              <i className="fas fa-store"></i> Pickup
            </button>
            <button 
              onClick={() => setOrderType('Delivery')}
              className={`p-4 rounded-2xl border-2 font-bold flex flex-col items-center gap-2 transition-all ${orderType === 'Delivery' ? 'border-emerald-500 bg-emerald-50 text-emerald-700' : 'border-slate-100 text-slate-400'}`}
            >
              <i className="fas fa-truck"></i> Delivery
            </button>
          </div>
          {orderType === 'Delivery' ? (
            <div className="animate-in fade-in slide-in-from-top-4 duration-300">
              <label className="text-sm font-semibold text-slate-500 block mb-1">Delivery Address</label>
              <textarea 
                value={address}
                onChange={(e) => setAddress(e.target.value)}
                placeholder="Enter your street address, apartment, and zip..." 
                className="w-full bg-slate-50 border-none rounded-2xl px-4 py-3 focus:ring-2 focus:ring-emerald-500 h-24 resize-none"
              ></textarea>
            </div>
          ) : (
            <div className="bg-slate-50 p-4 rounded-2xl text-sm text-slate-500">
              <i className="fas fa-info-circle mr-2"></i> Ready for pickup in 15-20 minutes at 123 Juice St.
            </div>
          )}
        </div>
      </div>

      <div className="space-y-6">
        <div className="bg-white p-8 rounded-3xl shadow-lg border border-slate-100 sticky top-24">
          <h3 className="text-xl font-bold text-slate-800 mb-6">Order Summary</h3>
          <div className="space-y-4 mb-6 max-h-48 overflow-y-auto pr-2">
            {cart.map(item => (
              <div key={item.id} className="flex justify-between text-sm">
                <span className="text-slate-600">{item.quantity}x {item.name}</span>
                <span className="font-semibold">${(item.price * item.quantity).toFixed(2)}</span>
              </div>
            ))}
          </div>

          {aiUpsell && (
            <div className="bg-orange-50 p-4 rounded-2xl border border-orange-100 mb-6">
              <div className="flex items-start gap-3">
                <div className="bg-orange-400 text-white w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 animate-pulse">
                  <i className="fas fa-star text-xs"></i>
                </div>
                <div>
                  <p className="text-xs font-bold text-orange-700 uppercase tracking-wider mb-1">AI Recommendation</p>
                  <p className="text-sm text-orange-800 mb-2">Want to add a <span className="font-bold">{aiUpsell.name}</span>? It pairs perfectly with your choice!</p>
                  <button 
                    onClick={() => {
                      addToCart(aiUpsell);
                      setAiUpsell(null);
                    }}
                    className="text-xs bg-orange-500 text-white px-3 py-1.5 rounded-full font-bold hover:bg-orange-600 transition-colors"
                  >
                    Add +${aiUpsell.price.toFixed(2)}
                  </button>
                </div>
              </div>
            </div>
          )}

          <div className="space-y-3 pt-6 border-t border-slate-100">
            <div className="flex justify-between text-slate-500">
              <span>Subtotal</span>
              <span>${cartSubtotal.toFixed(2)}</span>
            </div>
            {orderType === 'Delivery' && (
              <div className="flex justify-between text-slate-500">
                <span>Delivery Fee</span>
                <span>${DELIVERY_FEE.toFixed(2)}</span>
              </div>
            )}
            <div className="flex justify-between text-2xl font-black text-slate-800 pt-2">
              <span>Total</span>
              <span>${cartTotal.toFixed(2)}</span>
            </div>
          </div>

