import { GoogleGenAI } from "@google/genai";
import { Product, CartItem } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const geminiService = {
  // 1. AI Juice Descriptions
  async generateJuiceDescription(juiceName: string, ingredients: string[]): Promise<string> {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Write a short (max 12 words), appetizing description for a juice called "${juiceName}" containing ${ingredients.join(', ')}.`,
      });
      return response.text || "Freshly squeezed daily just for you.";
    } catch (error) {
      return "Deliciously fresh and nutrient-packed juice.";
    }
  },

  // 2. AI Customer Chatbot
  async getChatResponse(query: string): Promise<string> {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: query,
        config: {
          systemInstruction: `You are a friendly juice shop assistant at FreshPress. 
          Store hours: 8am-8pm. Location: 123 Juice Street. 
          Delivery fee: $3.50. We only use raw, organic fruits. 
          Be cheerful and keep answers under 2 sentences.`,
        }
      });
      return response.text || "I'm here to help! What would you like to know?";
    } catch (error) {
      return "FreshPress is juicing some new ideas! Please ask again in a second.";
    }
  },

  // 3. AI Upsell Suggestions
  async getUpsellSuggestion(cartItems: CartItem[], allProducts: Product[]): Promise<Product | null> {
    if (cartItems.length === 0) return null;
    try {
      const cartNames = cartItems.map(i => i.name).join(', ');
      const availableNames = allProducts.map(p => p.name).join(', ');

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Cart: [${cartNames}]. Available: [${availableNames}]. Pick exactly one juice name from 'Available' that pairs best. Respond with ONLY the juice name.`,
      });

      const suggestedName = response.text?.trim() || "";
      return allProducts.find(p => p.name.toLowerCase().includes(suggestedName.toLowerCase())) || null;
    } catch (error) {
      return null;
    }
  },

  // 4. AI Order Confirmation
  async generateConfirmationMessage(name: string): Promise<string> {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate a fun, 1-sentence juice-themed order confirmation for ${name}.`,
      });
      return response.text || "Your fresh squeeze is being prepared!";
    } catch (error) {
      return "Thanks for your order! We're starting on it now.";
    }
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { Product, CartItem, Order, Page, OrderType, OrderStatus } from './types';
import { INITIAL_PRODUCTS, DELIVERY_FEE } from './constants';
import { geminiService } from './services/geminiService';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [lastOrder, setLastOrder] = useState<Order | null>(null);

  // Checkout Form
  const [customerName, setCustomerName] = useState('');
  const [phone, setPhone] = useState('');
  const [orderType, setOrderType] = useState<OrderType>('Pickup');
  const [address, setAddress] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [aiUpsell, setAiUpsell] = useState<Product | null>(null);

  // Chatbot State
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [chatInput, setChatInput] = useState('');
  const [chatMessages, setChatMessages] = useState<{role: string, text: string}[]>([]);
  const [isChatLoading, setIsChatLoading] = useState(false);

  // Cart Management
  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === product.id);
      if (existing) return prev.map(i => i.id === product.id ? {...i, quantity: i.quantity + 1} : i);
      return [...prev, {...product, quantity: 1}];
    });
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(i => i.id === id ? {...i, quantity: Math.max(1, i.quantity + delta)} : i));
  };

  const removeFromCart = (id: string) => setCart(prev => prev.filter(i => i.id !== id));

  const subtotal = useMemo(() => cart.reduce((s, i) => s + (i.price * i.quantity), 0), [cart]);
  const total = useMemo(() => subtotal + (orderType === 'Delivery' ? DELIVERY_FEE : 0), [subtotal, orderType]);

  // AI Upsell Hook
  useEffect(() => {
    if (currentPage === 'checkout' && cart.length > 0) {
      geminiService.getUpsellSuggestion(cart, products).then(setAiUpsell);
    }
  }, [currentPage, cart, products]);

  const handleCheckout = async () => {
    if (!customerName || !phone || (orderType === 'Delivery' && !address)) {
      alert("Please fill in all required fields!");
      return;
    }
    setIsProcessing(true);
    await new Promise(r => setTimeout(r, 1500)); // Simulate Payment

    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 6).toUpperCase(),
      customerName,
      phone,
      items: [...cart],
      total,
      type: orderType,
      address,
      status: 'New',
      createdAt: Date.now()
    };

    setOrders(prev => [newOrder, ...prev]);
    setLastOrder(newOrder);
    setCart([]);
    setCustomerName('');
    setPhone('');
    setAddress('');
    setIsProcessing(false);
    setCurrentPage('confirmation');
  };

  const sendChatMessage = async () => {
    if (!chatInput.trim()) return;
    const userText = chatInput;
    setChatInput('');
    setChatMessages(prev => [...prev, {role: 'user', text: userText}]);
    setIsChatLoading(true);
    const response = await geminiService.getChatResponse(userText);
    setChatMessages(prev => [...prev, {role: 'bot', text: response}]);
    setIsChatLoading(false);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 sm:pb-0">
      {/* Header */}
      <nav className="bg-white/80 backdrop-blur-md border-b sticky top-0 z-50 px-4 h-16 flex items-center justify-between shadow-sm">
        <div onClick={() => setCurrentPage('home')} className="flex items-center gap-2 cursor-pointer">
          <div className="bg-emerald-500 p-1.5 rounded-lg text-white">
            <i className="fas fa-leaf"></i>
          </div>
          <span className="font-black text-xl tracking-tighter text-emerald-600">FRESHPRESS</span>
        </div>
        <div className="flex gap-4 items-center">
          <button onClick={() => setCurrentPage('admin')} className="text-xs font-bold text-slate-400 hover:text-slate-600">ADMIN</button>
          <button onClick={() => setCurrentPage('cart')} className="relative bg-emerald-100 p-2.5 rounded-full text-emerald-600 hover:bg-emerald-200 transition-colors">
            <i className="fas fa-shopping-bag"></i>
            {cart.length > 0 && <span className="absolute -top-1 -right-1 bg-orange-500 text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full ring-2 ring-white animate-pulse">{cart.length}</span>}
          </button>
        </div>
      </nav>

      {/* Pages */}
      <main className="max-w-4xl mx-auto p-4 sm:p-8">
        {currentPage === 'home' && (
          <div className="text-center py-20 space-y-8">
            <div className="relative inline-block">
               <img src="https://images.unsplash.com/photo-1610970881699-44a5587cabec?auto=format&fit=crop&q=80&w=600" className="w-64 h-64 rounded-full object-cover shadow-2xl border-8 border-white mx-auto" />
               <div className="absolute -bottom-4 -right-4 bg-orange-400 text-white p-4 rounded-full font-bold shadow-lg transform rotate-12">Fresh!</div>
            </div>
            <h1 className="text-5xl font-black text-slate-800 tracking-tight">Pure Juice. <br/>Pure Energy.</h1>
            <p className="text-slate-500 text-lg max-w-md mx-auto">Cold-pressed daily with local organic fruits. Order now for pickup or delivery.</p>
            <button onClick={() => setCurrentPage('menu')} className="bg-emerald-600 text-white px-10 py-5 rounded-3xl font-bold text-xl shadow-xl hover:scale-105 active:scale-95 transition-all">Start Your Order</button>
          </div>
        )}

        {currentPage === 'menu' && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <h2 className="text-3xl font-black text-slate-800">Fresh Menu</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
              {products.map(p => (
                <div key={p.id} className="bg-white rounded-[2rem] p-5 shadow-sm border hover:shadow-md transition-shadow flex gap-4 items-center">
