                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {currentPage === 'cart' && (
          <div className="space-y-6 max-w-lg mx-auto animate-in fade-in duration-300">
            <h2 className="text-3xl font-black text-slate-800">My Bag</h2>
            {cart.length === 0 ? (
