            ) : (
              <>
                <div className="space-y-3">
                  {cart.map(i => (
                    <div key={i.id} className="bg-white p-4 rounded-3xl flex items-center gap-4 shadow-sm">
                      <img src={i.image} className="w-16 h-16 rounded-xl object-cover" />
