// Always use the direct process.env.API_KEY for initialization as per guidelines
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const geminiService = {
  // 1. AI Juice Descriptions
  async generateJuiceDescription(juiceName: string, ingredients: string[]): Promise<string> {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Write a short (max 12 words), appetizing description for a juice called "${juiceName}" containing ${ingredients.join(', ')}.`,
      });
      return response.text || "Freshly squeezed daily just for you.";
    } catch (error) {
      return "Deliciously fresh and nutrient-packed juice.";
    }
  },

  // 2. AI Customer Chatbot
  async getChatResponse(query: string): Promise<string> {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: query,
        config: {
          systemInstruction: `You are a friendly juice shop assistant at FreshPress. 
          Store hours: 8am-8pm. Location: 123 Juice Street. 
          Delivery fee: $3.50. We only use raw, organic fruits. 
          Be cheerful and keep answers under 2 sentences.`,
        }
      });
      return response.text || "I'm here to help! What would you like to know?";
    } catch (error) {
      return "FreshPress is juicing some new ideas! Please ask again in a second.";
    }
  },

  // 3. AI Upsell Suggestions
  async getUpsellSuggestion(cartItems: CartItem[], allProducts: Product[]): Promise<Product | null> {
    if (cartItems.length === 0) return null;
    try {
      const cartNames = cartItems.map(i => i.name).join(', ');
      const availableNames = allProducts.map(p => p.name).join(', ');

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Cart: [${cartNames}]. Available: [${availableNames}]. Pick exactly one juice name from 'Available' that pairs best. Respond with ONLY the juice name.`,
      });

      const suggestedName = response.text?.trim() || "";
      return allProducts.find(p => p.name.toLowerCase().includes(suggestedName.toLowerCase())) || null;
    } catch (error) {
      return null;
    }
  },

  // 4. AI Order Confirmation
  async generateConfirmationMessage(name: string): Promise<string> {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate a fun, 1-sentence juice-themed order confirmation for ${name}.`,
      });
      return response.text || "Your fresh squeeze is being prepared!";
    } catch (error) {
      return "Thanks for your order! We're starting on it now.";
    }
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { geminiService } from '../services/geminiService';

const ChatBot: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{ role: 'user' | 'bot'; text: string }[]>([
    { role: 'bot', text: 'Hi! I am your FreshPress assistant. Ask me anything about our juices, hours, or delivery!' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    // Fix: getChatResponse only expects one argument 'query'
    const botResponse = await geminiService.getChatResponse(userMsg);
    setMessages(prev => [...prev, { role: 'bot', text: botResponse }]);
    setIsLoading(false);
  };

  return (
    <div className="fixed bottom-6 right-6 z-50">
      {isOpen ? (
        <div className="bg-white rounded-2xl shadow-2xl w-80 sm:w-96 flex flex-col overflow-hidden border border-slate-200">
          <div className="bg-emerald-600 p-4 text-white flex justify-between items-center">
            <h3 className="font-semibold flex items-center gap-2">
              <i className="fas fa-robot"></i> FreshBot Assistant
            </h3>
            <button onClick={() => setIsOpen(false)}><i className="fas fa-times"></i></button>
          </div>
          <div ref={scrollRef} className="h-80 overflow-y-auto p-4 space-y-4 bg-slate-50">
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] p-3 rounded-2xl text-sm ${
                  msg.role === 'user' ? 'bg-emerald-500 text-white rounded-tr-none' : 'bg-white border border-slate-200 text-slate-700 rounded-tl-none shadow-sm'
                }`}>
                  {msg.text}
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border border-slate-200 p-3 rounded-2xl rounded-tl-none shadow-sm text-slate-400">
                  <i className="fas fa-circle-notch animate-spin"></i> Thinking...
                </div>
              </div>
            )}
          </div>
          <div className="p-4 bg-white border-t flex gap-2">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Type a message..."
              className="flex-1 bg-slate-100 rounded-full px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500"
            />
            <button 
              onClick={handleSend}
              className="bg-emerald-600 text-white w-10 h-10 rounded-full flex items-center justify-center hover:bg-emerald-700 transition-colors"
            >
              <i className="fas fa-paper-plane"></i>
            </button>
          </div>
        </div>
      ) : (
        <button 
          onClick={() => setIsOpen(true)}
          className="bg-emerald-600 text-white w-14 h-14 rounded-full shadow-lg flex items-center justify-center hover:scale-105 active:scale-95 transition-all"
        >
          <i className="fas fa-comment-dots text-xl"></i>
        </button>
      )}
    </div>
  );
};

export default ChatBot;

